head.script:
// AS-IS 에 선언되어 있지만 사용하지 않고 있어서 주석 처리 (26.04.08)
// scwin.empNo = $c.data.getMemInfo("userId");

scwin.onpageload = function() {
	// 부모창에서 받아오는 파라미터
	scwin.params = $c.data.getParameter();

	// 작업시프트
	const codeOptions = [
		{ grpCd : "TB005", compID : "lc_wrkShift"},
	];
	$c.data.setCommonCode(codeOptions, scwin.commonCodeCallbackFunc);
};


//-------------------------------------------------------------------------
// 공통 코드 콜백함수 - 작업시프트(lc_wrkShift)
//-------------------------------------------------------------------------
scwin.commonCodeCallbackFunc = function() {
	$c.gus.cfSetValue(ed_wrkDt, scwin.params.ica_wrkDt);
	$c.gus.cfSetValue(lc_wrkShift, scwin.params.lc_wrkShift);
};


//-------------------------------------------------------------------------
// Windows Close
//-------------------------------------------------------------------------
scwin.f_WinClose = function() {
	$c.win.closePopup("");
};

//-------------------------------------------------------------------------
// Windows Return
//-------------------------------------------------------------------------
scwin.f_Apply = async function() {
	// ValidExp Setting
	$c.gus.setValidExp(ed_wrkDt, "작업일자:yes:length=8");
	$c.gus.setValidExp(lc_wrkShift, "작업일자:yes");

	let chk = await $c.gus.cfValidate([ed_wrkDt, lc_wrkShift], null, true);
	if (!chk) return;

	let returnValue = {
		"wrkDt": ed_wrkDt.getValue(),
		"wrkShift": lc_wrkShift.getValue()
	};

	$c.win.closePopup(returnValue);
};


// 적용 버튼
scwin.btn_apply_onclick = function (e) {
	scwin.f_Apply();
};

// 닫기 버튼
scwin.btn_close_onclick = function (e) {
	scwin.f_WinClose();
};
